import React from 'react';
import { Box, CssBaseline } from '@mui/material';
import NavigationDrawer from './components/NavigationDrawer';
import MainContent from './components/MainContent';

function App() {
  return (
    <Box sx={{ display: 'flex' }}>
      <CssBaseline />
      <NavigationDrawer />
      <MainContent />
    </Box>
  );
}

export default App;
